var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"이 아이들이 바로 <color=#ffd34c>지식의 호수</color>예요.","JPN":"この子たちこそが<color=#ffd34c>知識の湖</color>なんです。","ENG":"They are the <color=#ffd34c>Lake of Knowledge</color>.","TWN":"這些孩子就是<color=#ffd34c>知識之湖</color>。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"세상의 모든 지식을 담을 수 있는 서고죠.","JPN":"この世のすべての知識を宿せる書庫なんですよ。","ENG":"An archive that's able to store all the knowledge in this world.","TWN":"是能夠收納世界上所有知識的書庫。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 촉수들이...... 지식의 호수라고요?","JPN":"その触手が……知識の湖？","ENG":"Those tentacles... They're the Lake of Knowledge?","TWN":"妳說這些觸手……是知識之湖？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼 학회는 여태 코앞에 있는 호수를 내버려 두고 헛된 짓만 했단 말인가요?","JPN":"つまり、学会はこんな目の前に湖があるのに、湖を探していたということですか？","ENG":"Then what has the Society been doing all along? The Lake has been right under their noses!","TWN":"也就是學會放著眼前的知識之湖不管，都在做些沒用的事情？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"호수는 완전하지 않아요.","JPN":"湖は完全ではありません。","ENG":"The Lake is incomplete.","TWN":"湖並不完整。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"오래 전...... 아주 오래 전에 수많은 조각으로 나눠져서 뿔뿔이 흩어졌거든요.","JPN":"遥か昔……気が遠くなるほど昔に、多くのカケラに分けられて散り散りになってしまいましたから。","ENG":"Long ago, it was split into numerous pieces and scattered across the world.","TWN":"很久以前……很久很久以前，它被分成很多碎片，散落在各地。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"책에 비유하면 낱장이나 글자가 사라져 버린 셈이죠.","JPN":"本で言えば、ページや文字が消えてしまっている状態ですね。","ENG":"Now it's like a book with pages ripped out and words and letters missing.","TWN":"用書來比喻的話，就是其中的書頁或文字消失了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그래서 이 아이들은 무척 예민해요.","JPN":"そのせいで、この子たちもかなり気が立っているんですよ。","ENG":"That's why they are very sensitive.","TWN":"所以這些孩子們非常敏感。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"항상 누군가가 곁에서 돌봐 줘야 말썽을 피우지 않죠.","JPN":"常に誰かが傍で世話をしないと暴れ出すんです。","ENG":"You always need to take care of them so that they won't cause any trouble.","TWN":"必須時時有人在身旁照顧，它們才不會惹出麻煩。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"이건 학회장의 역할 중에서도 가장 중요한 직무랍니다.","JPN":"これは学会長の役割の中でも、最も重要な職務です。","ENG":"It's the most important duty of the President of the Society.","TWN":"這也是學會長的職務中最重要的工作。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그럼...... 계승식이라는 건......","JPN":"じゃあ……継承式というのは……","ENG":"You mean... the succession ceremony is...","TWN":"那……所謂繼承儀式……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"설마 그 괴물들을 다음 학회장 몸으로 옮기기 위한 의식인가요?","JPN":"まさか、その怪物を次の学会長の体に移すための儀式なのですか？","ENG":"the event where you transfer those monsters from the former President to the next one?","TWN":"該不會就是為了把這些怪物轉移到下任學會長的身體裡吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"맞아요. 이해가 무척 빠르시네요.","JPN":"ええ。理解が早くて助かります。","ENG":"Precisely. You're very quick to understand.","TWN":"沒錯。您理解得很快呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"역시 레지나 님은 훌륭한 차기 학회장감이세요.","JPN":"やっぱり、レジーナ様は立派な次期学会長になれそうですね。","ENG":"We knew you were a perfect material for the next President of the Society.","TWN":"蕾佳娜大人果然是優秀的下任學會長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"음, 음. 육아 하면 레지나지. 적성이랑 잘 맞겠네.","JPN":"うんうん。育児と言えばレジーナだよね。向いてると思うよ。","ENG":"Uh-huh. Regina's the one if you're looking for someone to take care of babies. She's a good fit for the job.","TWN":"嗯，嗯。說到養小孩就想到蕾佳娜， 相性果然很合呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신은 누구 맘대로 남의 적성을 결정해요?! 제 진로는 고고학으로 정해져 있습니다!","JPN":"勝手に人の向き不向きを決めないでもらえますか！？　私の進路は考古学と決めているのです！","ENG":"What are you to decide what I'm good at? My career path will be in archaeology!","TWN":"妳憑什麼隨便決定別人的相性啊？我已經決定要走考古學的道路了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어쨌든......","JPN":"とにかく……","ENG":"Anyway...","TWN":"總之……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 말대로라면 당신이 하는 식사는 누락된 정보를 다시 채우려는 거군요.","JPN":"言葉通りならば……あなたの食事というのは、抜け落ちた情報を集めることなのですね。","ENG":"If what you're saying it true, you're eating things to fill in the missing information.","TWN":"按照妳的說法，所謂的用餐就是補足缺失的情報吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"맞아요. 책이라면 자신의 내용이 풍부하기를 바라지 않겠어요?","JPN":"その通りです。本ならば、自分に内容が詰まっていることを望むものでしょう？","ENG":"Correct. A book should be rich in content, shouldn't it?","TWN":"沒錯。作為一本書，妳不會希望自己內容很豐富嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그렇다고 침식체까지 닥치는 대로 먹어 치워야 할 필요는 없잖아요.","JPN":"でも、侵食体まで手当たり次第に食い尽くす必要はないのでは？","ENG":"But do you really have to eat crazy things like those C.O.s?","TWN":"就算是這樣，妳也沒必要連侵蝕體都要整隻吃掉吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"지식을 얻고 싶으면 책을 읽어도 되죠.","JPN":"知識を得たければ本を読めばいいでしょう？","ENG":"If knowledge is what you're after, you could just read.","TWN":"想獲得知識的話，只要看書就行了吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"하지만 독서보다 놀라울 만큼 흡수도 빠르고 영양가도 풍부하답니다.","JPN":"ですが、読書よりも驚くほど吸収が早く、栄養も豊富なんですよ。","ENG":"But eating is a much faster process, and we can get nutrients from it.","TWN":"但是比起讀書，用這種方式攝取知識吸收速度更驚人，營養也更豐富。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"제가 보기에 안 좋다고요, 제가 보기에.","JPN":"私がそうとは思えないのです、私が。","ENG":"But it's gross! Absolutely gross!","TWN":"我覺得不好啊，完全不好。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"식사는 자고로......","JPN":"食事というものはですね……","ENG":"A meal should be...","TWN":"自古以來，用餐就該……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그래, 품위를 지켜야죠!","JPN":"そう、まず品位を保たなければなりませんわ！","ENG":"It should be had gracefully, don't you think?","TWN":"沒錯，就該保持用餐禮儀及品味！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그쪽을 지적하는 걸 보니 너도 생각보다 맛이 많이 갔구나?","JPN":"まずそこを指摘するところを見ると、アンタも意外と正気じゃないね。","ENG":"Really? That's your argument? You're more messed up than I thought.","TWN":"妳竟然指責起她來了，看來妳也不太正常了啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"왜 계속 말하는 족족 딴지를 못 걸어서 안달이에요?","JPN":"どうして何か言うたびにケチを付けようとするのです？","ENG":"Do you really have to pick on every word I say?","TWN":"妳幹嘛老是找我碴？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그야 즐거운 커뮤니케이션을 하기엔 때와 장소가 적절하지 않거든.","JPN":"そりゃ、楽しいコミュニケーションをするには時と場所がふさわしくないからね。","ENG":"It's because this isn't the right place or time for a pleasant conversation.","TWN":"因為這不是個適合交流的愉快時間和地點啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신! 그 아무데나 쏘고 보는 버릇 못 고치겠어?! 불이라도 나면 어쩌려고 그래!","JPN":"あなたは！　その確認もしないで撃つ癖、何とかなりませんか！？　火事にでもなったらどうするのです！","ENG":"Hey! Will you lose your shoot-first think-later attitude? What if you start a fire in the forest?","TWN":"妳！妳能不能改掉這個到處亂開槍的習慣？！要是走火了怎麼辦！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아까부터 우릴 노리던 녀석들에게 한 방 먹여 줬을 뿐이야.","JPN":"さっきからアタシたちを狙ってたやつらに一発お見舞いしただけだよ。","ENG":"I just wanted to teach them a lesson for trying to come at us.","TWN":"我只是送了一發，給那些從剛才就盯著我們看的傢伙而已。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"싸움은 먼저 때리는 쪽이 이긴다잖아? 꺄하하하!","JPN":"先手必勝って言うしね。キャハハハ！","ENG":"You know what they say, first to throw a fist wins the fight. Kya hah hah hah!","TWN":"打架的時候不是先打先贏嘛？哈哈哈哈！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아지트에서 본 괴물들......?! 어느 틈에 쫓아온 거죠?","JPN":"アジトで見た怪物……！？　いつの間に追って来たのでしょうか？","ENG":"The monsters from the hideout! Have they been following us?","TWN":"在基地裡看到的怪物……？！它們是什麼時候追上來的啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"오는 동안 따라붙은 녀석들은 없었어. 처음부터 우리가 오기만을 기다렸던 것 같아.","JPN":"来る時に追って来る奴はいなかったよ。最初からアタシたちが来るのを待ってたみたい。","ENG":"There was nothing following us on our way here. It seems they've been waiting here for us from the beginning.","TWN":"這些傢伙不是追著我們過來的，而像是從一開始就在這裡等我們。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에델, 식후 운동 겸 좀 거들어 줄래?","JPN":"エデル、食後の運動がてら、ちょっと手伝ってくれる？","ENG":"Edel, do you mind a little post-meal exercise?","TWN":"艾瑟兒，就當作是飯後運動，稍微來幫個忙吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"물론이죠. 마침 다시 출출해진 참이었거든요.","JPN":"もちろんです。ちょうどまたお腹が空いてきたところでしたから。","ENG":"That sounds nice. We were getting hungry again, actually.","TWN":"當然可以。我們正好又有有點餓了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"다, 당신은 아지트에서 에델에게 먹힐 뻔하고도 그런 소리가 입 밖으로 나와요?!","JPN":"あ、あなたはアジトでエデルに食べられかけたのに、よくそんなことを言えますね！？","ENG":"H-how can you say these things when she almost ate you up back at the hideout?","TWN":"妳、妳在基地差點被艾瑟兒吃掉了耶，怎麼還說得出這種話？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에이, 그 정도로 겁내면 용병 일로 입에 풀칠하긴 힘들지.","JPN":"ねえ、あれくらいでビビってたら傭兵の仕事で食っていけないよ。","ENG":"Come on, how am I supposed to call myself a mercenary if I let something like that hold me back?","TWN":"這個嘛，這樣就怕的話，要當傭兵可是很難的啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그리고 에델도 실컷 먹은 만큼 당분간은 잠잠할 거야.","JPN":"それにエデルも思いっきり食べたから、しばらくはおとなしいと思うけど。","ENG":"Besides, Edel has eaten enough for the day. She'll be all right for now.","TWN":"而且艾瑟兒也盡情地大吃了一頓，暫時不會再失去理智了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"내 말 맞지, 에델?","JPN":"エデル、そうでしょ？","ENG":"Back me up here, Edel.","TWN":"對吧，艾瑟兒？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"죄송해요. 확신은 못 드리겠네요.","JPN":"すみませんが、断言はできません。","ENG":"Sorry. There's no guarantee.","TWN":"對不起，我們不是很確定呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"EDEL_ESPR_SHADOW_NULL","text":{"KOREA":"이 아이들은 한창 때라 식욕이 왕성하거든요.","JPN":"この子たちは育ち盛りなので、食欲がすごく旺盛なんですよ。","ENG":"These babies tend to get hungry very often.","TWN":"畢竟這些孩子都很年輕，食欲都很旺盛。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDEL_ESPR_SHADOW_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"봐, 그렇다잖아!","JPN":"ほらね！","ENG":"See?","TWN":"妳看，我就說吧！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"대체 뭐가 그렇다는 거예요?!","JPN":"何がほらね、なんですか！？","ENG":"See what? Are you listening to yourself?","TWN":"妳到底說了什麼？！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......그래도 당장 저 괴물들에게 잡아먹히는 것보단 낫겠죠.","JPN":"……それでも、今あの怪物どもに食べられるよりはマシでしょう。","ENG":"But... Fine, it'd be much better than letting those monsters chew on me.","TWN":"……但總比直接被這些怪物吃掉來得好吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"접근은 제가 막겠어요! 뒤를 부탁합니다!","JPN":"接近は私が阻止します！　後をお願いします！","ENG":"I'll hold them back. Watch my back, please!","TWN":"我來攔住接近的敵人！背後就交給你們了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};